insert into public.raw_calendar_rows (
  calendar_id,
  source_id,
  date,
  raw_title,
  raw_rank,
  raw_color,
  raw_notes,
  country_scope
)
select
  'us',
  source.id,
  raw_rows.date,
  raw_rows.raw_title,
  raw_rows.raw_rank,
  raw_rows.raw_color,
  raw_rows.raw_notes,
  raw_rows.country_scope
from source
cross join raw_rows;

with source as (
  select id
  from public.calendar_sources
  where calendar_id = 'us'
    and year = 2026
    and url = 'https://www.usccb.org/resources/2026cal.pdf'
  order by retrieved_at desc
  limit 1
),
days (
  date,
  weekday,
  weekday_name,
  celebration_id,
  title,
  display_title,
  season,
  season_week,
  psalter_week,
  rank,
  color,
  country_scope,
